OME CARDS ── */\n.home-cards{width:100%;display:grid;grid-template-columns:1fr 1fr;gap:14px;padding:0 0.25rem}\n.home-card{background:#fff;border:1.5px solid #dad6f9;border-radius:20px;padding:1.5rem 1rem 1.25rem;text-align:center;cursor:pointer;transition:transform 0.25s,border-color 0.25s,box-shadow 0.25s;display:flex;flex-direction:column;align-items:center;gap:10px;box-shadow:0 4px 16px rgba(91,79,204,0.10)}\n.home-card:hover{transform:translateY(-6px);border-color:#7b6fe8;box-shadow:0 8px 28px rgba(91,79,204,0.18)}\n.home-card:active{transform:scale(0.97)}\n.home-card.primary{background:#5b4fcc;border-color:#5b4fcc;box-shadow:0 6px 22px rgba(91,79,204,0.32)}\n.home-card.primary:hover{box-shadow:0 10px 32px rgba(91,79,204,0.42)}\n.card-icon-wrap{width:62px;height:62px;border-radius:18px;display:flex;align-items:center;justify-content:center;position:relative;transition:transform 0.3s;box-shadow:0 4px 14px rgba(0,0,0,0.13)}\n.home-card:hover .card-icon-wrap{transform:rotate(-6deg) scale(1.12)}\n.card-title{font-family:\'Amiri\',serif;font-size:20px;font-weight:700;color:#2d2566;letter-spacing:0.3px}\n.home-card.primary .card-title{color:#fff}\n.card-desc{font-size:12px;color:#7c6fc9;line-height:1.55;font-weight:500}\n.home-card.primary .card-desc{color:#c5bfef}\n\n/* ── STATS ROW ── */\n.stats-row{display:flex;gap:20px;padding:0.25rem 0;align-items:center}\n.stat-item{text-align:center}\n.stat-num{font-family:\'Cairo\',sans-serif;font-size:22px;font-weight:900;color:#5b4fcc}\n.stat-lbl{font-size:11px;color:#9b8fe0;font-weight:600}\n.stat-div{width:1px;background:#e0dcfa;align-self:stretch}\n\n/* ── HIGH SCORE ── */\n.highscore-banner{width:100%;background:#fff;border:1.5px solid #dad6f9;border-radius:16px;padding:0.75rem 1.25rem;display:flex;align-items:center;justify-content:space-between;box-shadow:0 2px 10px rgba(91,79,204,0.08)}\n.hs-label{font-size:12px;color:#9b8fe0;font-weight:600;display:flex;align-items:center;gap:6px}\n.hs-value{font-family:\'Cairo\',sans-serif;font-size:20px;font-weight:900;color:#5b4fcc}\n.hs-value.pop{animation:hsPop 0.6s cubic-bezier(0.36,0.07,0.19,0.97)}\n@keyframes hsPop{0%{transform:scale(1)}40%{transform:scale(1.3)}70%{transform:scale(0.95)}100%{transform:scale(1)}}\n\n/* ── SETTINGS / REVIEW ── */\n.screen-header{width:100%;display:flex;align-items:center;gap:10px}\n.back-btn{background:#fff;border:1.5px solid #dad6f9;border-radius:50px;padding:7px 16px;font-family:\'Cairo\',sans-serif;font-size:13px;font-weight:600;color:#5b4fcc;cursor:pointer;transition:all 0.2s;display:flex;align-items:center;gap:6px}\n.back-btn:hover{background:#eeedfe}\n.screen-title{font-family:\'Amiri\',serif;font-size:21px;font-weight:700;color:#2d2566}\n.settings-panel{width:100%;background:#fff;border-radius:20px;border:1.5px solid #e0dcfa;overflow:hidden}\n.settings-row{display:flex;align-items:center;justify-content:space-between;padding:1rem 1.25rem;border-bottom:1px solid #f0eeff;gap:12px}\n.settings-row:last-child{border-bottom:none}\n.settings-label{display:flex;align-items:center;gap:10px;font-size:15px;font-weight:600;color:#2d2566}\n.settings-label i{font-size:20px;color:#7b6fe8}\n.s-sub{display:block;font-size:11px;color:#9b8fe0;font-weight:400;margin-top:1px}\n.toggle-track{width:48px;height:26px;border-radius:50px;background:#dbd8f7;position:relative;cursor:pointer;transition:background 0.25s;flex-shrink:0}\n.toggle-track.on{background:#5b4fcc}\n.toggle-thumb{width:20px;height:20px;border-radius:50%;background:#fff;position:absolute;top:3px;right:3px;transition:transform 0.25s}\n.toggle-track.on .toggle-thumb{transform:translateX(-22px)}\n.vol-row{display:flex;align-items:center;gap:10px;flex:1}\n.vol-slider{flex:1;height:5px;border-radius:50px;-webkit-appearance:none;appearance:none;background:#dbd8f7;outline:none;cursor:pointer}\n.vol-slider::-webkit-slider-thumb{-webkit-appearance:none;width:18px;height:18px;border-radius:50%;background:#5b4fcc;cursor:pointer}\n.vol-val{font-size:13px;font-weight:700;color:#5b4fcc;min-width:30px;text-align:center}\n\n/* ── REVIEW ── */\n.lesson-card{background:#fff;border:1px solid #e5e2fa;border-radius:16px;padding:1rem 1.25rem;width:100%;cursor:pointer;transition:all 0.2s;display:flex;align-items:center;gap:14px}\n.lesson-card:hover{border-color:#7b6fe8;background:#f7f5ff;transform:translateX(-3px)}\n.lesson-icon-box{width:42px;height:42px;border-radius:12px;display:flex;align-items:center;justify-content:center;flex-shrink:0}\n.lesson-name{font-family:\'Cairo\',sans-serif;font-size:15px;font-weight:700;color:#2d2566}\n.lesson-sub{font-size:11px;color:#9b8fe0;margin-top:2px}\n.lesson-detail{display:none;background:#f7f5ff;border:1px solid #e0dcfa;border-radius:14px;padding:1rem 1.25rem;width:100%;font-family:\'Cairo\',sans-serif;font-size:14px;color:#3d3273;line-height:1.9;white-space:pre-wrap}\n.lesson-detail.open{display:block;animation:slideDown 0.25s ease}\n@keyframes slideDown{from{opacity:0;transform:translateY(-8px)}to{opacity:1;transform:translateY(0)}}\n\n/* ── QUIZ ── */\n.quiz-navbar{width:100%;display:flex;justify-content:space-between;align-items:center}\n.score-pill{background:#5b4fcc;color:#fff;font-family:\'Cairo\',sans-serif;font-size:14px;font-weight:700;padding:7px 18px;border-radius:50px;display:flex;align-items:center;gap:6px}\n.hearts-row{width:100%;display:flex;gap:5px;align-items:center;justify-content:center;flex-wrap:wrap}\n.heart-ico{font-size:16px;transition:all 0.45s cubic-bezier(.36,.07,.19,.97);display:inline-block}\n.heart-ico.lost{opacity:0.15;transform:scale(0.7) rotate(-15deg)}\n.heart-ico.pulse{animation:hpulse 0.5s ease}\n.heart-ico.shake{animation:hshake 0.55s ease}\n@keyframes hpulse{0%{transform:scale(1)}40%{transform:scale(1.45)}100%{transform:scale(1)}}\n@keyframes hshake{0%{transform:translateX(0) rotate(0)}15%{transform:translateX(-7px) rotate(-10deg)}30%{transform:translateX(7px) rotate(10deg)}45%{transform:translateX(-5px) rotate(-6deg)}60%{transform:translateX(5px) rotate(6deg)}75%{transform:translateX(-3px)}100%{transform:translateX(0) rotate(0)}}\n\n.prog-wrap{width:100%}\n.prog-info{display:flex;justify-content:space-between;margin-bottom:7px}\n.prog-label,.prog-pct{font-size:12px;color:#7c6fc9;font-weight:600}\n.prog-track{height:8px;background:#dbd8f7;border-radius:50px;overflow:hidden}\n.prog-fill{height:100%;background:#5b4fcc;border-radius:50px;transition:width 0.6s cubic-bezier(0.4,0,0.2,1)}\n\n/* ── TIMER ── */\n.timer-wrap{width:100%;display:flex;align-items:center;gap:10px}\n.timer-track{flex:1;height:8px;background:#dbd8f7;border-radius:50px;overflow:hidden}\n.timer-fill{height:100%;background:#5b4fcc;border-radius:50px;transition:width 1s linear}\n.timer-fill.warning{background:#e67e22}\n.timer-fill.danger{background:#e74c3c}\n.timer-num{font-family:\'Cairo\',sans-serif;font-size:14px;font-weight:900;color:#5b4fcc;min-width:26px;text-align:center;transition:color 0.3s}\n.timer-num.warning{color:#e67e22}\n.timer-num.danger{color:#e74c3c;animation:timerPulse 0.5s ease infinite}\n@keyframes timerPulse{0%,100%{transform:scale(1)}50%{transform:scale(1.18)}}\n\n.q-card{background:#fff;border-radius:22px;border:1.5px solid #e0dcfa;padding:1.5rem 1.25rem;width:100%;text-align:center;display:flex;flex-direction:column;align-items:center;gap:0.8rem}\n.q-badge{font-size:12px;color:#7b6fe8;font-weight:700;background:#eeedfe;padding:5px 16px;border-radius:50px}\n.q-text{font-family:\'Amiri\',serif;font-size:21px;font-weight:700;color:#2d2566;line-height:1.65}\n.opts-grid{width:100%;display:grid;grid-template-columns:1fr 1fr;gap:11px}\n.opt{background:#fff;border:1.5px solid #dad6f9;border-radius:16px;padding:12px 8px;font-family:\'Cairo\',sans-serif;font-size:14px;font-weight:600;color:#3d3273;cursor:pointer;transition:all 0.22s cubic-bezier(0.4,0,0.2,1);text-align:center;direction:rtl;line-height:1.4}\n.opt:hover:not(:disabled){border-color:#7b6fe8;color:#4a3db8;transform:translateY(-3px)}\n.opt:active:not(:disabled){transform:scale(0.