tyle=\"background:#7c6fe8\">\n          <svg width=\"34\" height=\"34\" viewBox=\"0 0 34 34\" fill=\"none\" xmlns=\"http://www.w3.org/2000/svg\" aria-hidden=\"true\">\n            <ellipse cx=\"17\" cy=\"29\" rx=\"7\" ry=\"2.2\" fill=\"rgba(255,255,255,0.25)\"/>\n            <rect x=\"14.5\" y=\"24\" width=\"5\" height=\"5\" rx=\"1.5\" fill=\"white\" opacity=\"0.95\"/>\n            <rect x=\"11\" y=\"27.5\" width=\"12\" height=\"2.5\" rx=\"1.25\" fill=\"white\" opacity=\"0.95\"/>\n            <path d=\"M10 6h14l-2 12a5 5 0 01-10 0L10 6z\" fill=\"white\" opacity=\"0.95\"/>\n            <path d=\"M10 8H7a3 3 0 003 3\" stroke=\"white\" stroke-width=\"1.8\" stroke-linecap=\"round\" fill=\"none\" opacity=\"0.8\"/>\n            <path d=\"M24 8h3a3 3 0 01-3 3\" stroke=\"white\" stroke-width=\"1.8\" stroke-linecap=\"round\" fill=\"none\" opacity=\"0.8\"/>\n            <path d=\"M14 11l1.5 2 3.5-4\" stroke=\"#7c6fe8\" stroke-width=\"1.6\" stroke-linecap=\"round\" stroke-linejoin=\"round\"/>\n          </svg>\n        </div>\n        <div class=\"card-title\">ابدأ المباراة</div>\n        <div class=\"card-desc\">أجب على الأسئلة<br>واكسب النقاط</div>\n      </div>\n\n      <!-- بطاقة المراجعة -->\n      <div class=\"home-card\" onclick=\"goReview()\">\n        <div class=\"card-icon-wrap\" style=\"background:#4a90d9\">\n          <svg width=\"34\" height=\"34\" viewBox=\"0 0 34 34\" fill=\"none\" xmlns=\"http://www.w3.org/2000/svg\" aria-hidden=\"true\">\n            <path d=\"M17 26C17 26 9 22 6 10V7a1 1 0 011-1c3 0 7 1.5 10 4z\" fill=\"white\" opacity=\"0.95\"/>\n            <path d=\"M17 26C17 26 25 22 28 10V7a1 1 0 00-1-1c-3 0-7 1.5-10 4z\" fill=\"white\" opacity=\"0.75\"/>\n            <line x1=\"17\" y1=\"10\" x2=\"17\" y2=\"26\" stroke=\"rgba(74,144,217,0.6)\" stroke-width=\"1.2\"/>\n            <path d=\"M10 12l4 1.5\" stroke=\"white\" stroke-width=\"1.4\" stroke-linecap=\"round\" opacity=\"0.7\"/>\n            <path d=\"M10 15.5l4 1.5\" stroke=\"white\" stroke-width=\"1.4\" stroke-linecap=\"round\" opacity=\"0.7\"/>\n            <path d=\"M10 19l4 1.5\" stroke=\"white\" stroke-width=\"1.4\" stroke-linecap=\"round\" opacity=\"0.7\"/>\n            <path d=\"M6 27h22\" stroke=\"white\" stroke-width=\"2\" stroke-linecap=\"round\" opacity=\"0.6\"/>\n          </svg>\n        </div>\n        <div class=\"card-title\">مراجعة الدروس</div>\n        <div class=\"card-desc\">راجع المعلومات<br>قبل المباراة</div>\n      </div>\n    </div>\n\n    <div class=\"stats-row\">\n      <div class=\"stat-item\"><div class=\"stat-num\">20</div><div class=\"stat-lbl\">سؤالاً</div></div>\n      <div class=\"stat-div\"></div>\n      <div class=\"stat-item\"><div class=\"stat-num\">10</div><div class=\"stat-lbl\">قلوب</div></div>\n      <div class=\"stat-div\"></div>\n      <div class=\"stat-item\"><div class=\"stat-num\">20</div><div class=\"stat-lbl\">ثانية</div></div>\n      <div class=\"stat-div\"></div>\n      <div class=\"stat-item\"><div class=\"stat-num\">2000</div><div class=\"stat-lbl\">نقطة</div></div>\n    </div>\n\n    <!-- High Score Banner -->\n    <div class=\"highscore-banner\">\n      <div class=\"hs-label\"><i class=\"ti ti-crown\" style=\"font-size:16px;color:#f39c12\"></i> أعلى نتيجة</div>\n      <div style=\"display:flex;align-items:baseline;gap:4px\">\n        <span class=\"hs-value\" id=\"hsValue\">&#8212;</span>\n        <span style=\"font-size:11px;color:#9b8fe0;font-weight:600\">نقطة</span>\n      </div>\n    </div>\n  </div>\n\n  <!-- ██ SETTINGS ██ -->\n  <div class=\"screen\" id=\"sSettings\">\n    <div class=\"screen-header\">\n      <button class=\"back-btn\" onclick=\"goBack()\"><i class=\"ti ti-arrow-right\" style=\"font-size:14px\"></i> رجوع</button>\n      <span class=\"screen-title\"><i class=\"ti ti-settings\" style=\"font-size:19px;vertical-align:-3px;color:#5b4fcc\"></i> الإعدادات</span>\n      <button class=\"back-btn\" onclick=\"goHome()\" style=\"margin-right:auto\"><i class=\"ti ti-home\" style=\"font-size:14px\"></i> الرئيسية</button>\n    </div>\n    <div class=\"settings-panel\">\n      <div class=\"settings-row\">\n        <div class=\"settings-label\"><i class=\"ti ti-volume\"></i><div><span>الأصوات</span><span class=\"s-sub\">تفعيل أصوات المباراة</span></div></div>\n        <div class=\"toggle-track on\" id=\"sfxToggle\" onclick=\"toggleSfx()\"><div class=\"toggle-thumb\"></div></div>\n      </div>\n      <div class=\"settings-row\">\n        <div class=\"settings-label\"><i class=\"ti ti-music\"></i><div><span>مستوى الصوت</span><span class=\"s-sub\">اضبط الشدة</span></div></div>\n        <div class=\"vol-row\">\n          <i class=\"ti ti-volume-2\" style=\"font-size:16px;color:#9b8fe0\"></i>\n          <input class=\"vol-slider\" type=\"range\" min=\"0\" max=\"100\" value=\"70\" id=\"volSlider\" step=\"1\" oninput=\"changeVol(this.value)\">\n          <i class=\"ti ti-volume\" style=\"font-size:16px;color:#5b4fcc\"></i>\n          <span class=\"vol-val\" id=\"volVal\">70</span>\n        </div>\n      </div>\n      <div class=\"settings-row\">\n        <div class=\"settings-label\"><i class=\"ti ti-bell\"></i><div><span>صوت الفوز</span><span class=\"s-sub\">صوت عند الإجابة الصحيحة</span></div></div>\n        <div class=\"toggle-track on\" id=\"winToggle\" onclick=\"toggleWin()\"><div class=\"toggle-thumb\"></div></div>\n      </div>\n      <div class=\"settings-row\">\n        <div class=\"settings-label\"><i class=\"ti ti-alert-triangle\"></i><div><span>صوت الخطأ</span><span class=\"s-sub\">صوت عند الإجابة الخاطئة</span></div></div>\n        <div class=\"toggle-track on\" id=\"errToggle\" onclick=\"toggleErr()\"><div class=\"toggle-thumb\"></div></div>\n      </div>\n      <div class=\"settings-row\">\n        <div class=\"settings-label\"><i class=\"ti ti-test-pipe\"></i><div><span>اختبار الصوت</span><span class=\"s-sub\">استمع للأصوات</span></div></div>\n        <div style=\"display:flex;gap:8px\">\n          <button class=\"btn-prim\" style=\"padding:7px 14px;font-size:12px\" onclick=\"playSound(\'correct\')\"><i class=\"ti ti-check\"></i></button>\n          <button class=\"btn-sec\" style=\"padding:6px 14px;font-size:12px\" onclick=\"playSound(\'wrong\')\"><i class=\"ti ti-x\"></i></button>\n        </div>\n      </div>\n    </div>\n    <button class=\"btn-prim\" onclick=\"goHome()\"><i class=\"ti ti-home\" style=\"font-size:16px\"></i> العودة للرئيسية</button>\n  </div>\n\n  <!-- ██ REVIEW ██ -->\n  <div class=\"screen\" id=\"sReview\">\n    <div class=\"screen-header\">\n      <button class=\"back-btn\" onclick=\"goHome()\"><i class=\"ti ti-arrow-right\" style=\"font-size:14px\"></i> رجوع</button>\n      <span class=\"screen-title\"><i class=\"ti ti-book-2\" style=\"font-size:19px;vertical-align:-3px;color:#5b4fcc\"></i> مراجعة الدروس</span>\n    </div>\n    <div id=\"lessonsContainer\" style=\"width:100%;display:flex;flex-direction:column;gap:10px\"></div>\n    <button class=\"btn-prim\" onclick=\"goQuiz()\"><i class=\"ti ti-trophy\" style=\"font-size:16px\"></i> ابدأ المباراة الآن</button>\n  </div>\n\n  <!-- ██ QUIZ ██ -->\n  <div class=\"screen\" id=\"sQuiz\">\n    <div class=\"quiz-navbar\">\n      <button class=\"back-btn\" onclick=\"confirmHome()\" style=\"padding:7px 14px\">\n        <i class=\"ti ti-home\" style=\"font-size:14px\"></i> رجوع\n      </button>\n      <div style=\"display:flex;align-items:center;gap:8px\">\n        <div class=\"score-pill\"><i class=\"ti ti-star\" style=\"font-size:14px\"></i><span id=\"scoreTxt\">0</span></div>\n        <button class=\"back-btn\" style=\"padding:7px 12px;min-width:unset\" onclick=\"openSettings()\" title=\"الإعدادات\">\n          <i class=\"ti ti-settings\" style=\"font-size:15px;margin:0\"></i>\n        </button>\n      </div>\n    </div>\n    <div class=\"hearts-row\" id=\"heartsRow\"></div>\n    <div class=\"prog-wrap\">\n      <div class=\"prog-info\">\n        <span class=\"prog-label\" id=\"progLabel\">السؤال ١ من ٢٠</span>\n        <span class=\"prog-pct\" id=\"progPct\">&#x0665;&#x066A;</span>\n      </div>\n      <div class=\"prog-track\"><div class=\"prog-fill\" id=\"progFill\" style=\"width:5%\"></div></div>\n    </div>\n    <div class=\"timer-wrap\">\n      <i class=\"ti ti-clock\" style=\"font-size:16px;color:#9b8fe0\"></i>\n      <div class=\"timer-track\"><div class=\"timer-fill\" id=\"timerFill\" style=\"width:100%\"></div></div>\n      <span class=\"timer-num\" id=\"timerNum\">20</span>\n    </div>\n    <div class=\"q-card\" id=\"qCard\">\n      <span class=\"q-badge\" id=\"qBadge\">سؤال ١</span>\n      <p class=\"q-text\" id=\"qText\"></p>\n    </div>\n    <div class=\"opts-grid\" id=\"optsGrid\"></div>\n    <div class=\"feedback\" id=\"feedback\"></div>\n    <button class=\"next-btn\" id=\"nextBtn\" onclick=\"nextQ()\">\n      <span id=\"nextTxt\">السؤال التالي</span>\n      <i class=\"ti ti-arrow-left\" style=\"font-size:17px\"></i>\n    </button>\n  </div>\n\n  <!-- ██ GAME OVER ██ -->\n  <div class=\"screen\" id=\"sGameOver\">\n    <div class=\"end-card\" style=\"border-color:#fcc\">\n      <div class=\"end-icon\">&#x1F494;</div>\n      <div class=\"end-title\" style=\"color:#c0392b\">انتهت المباراة!</div>\n      <div id=\"goHeartsRow\" style=\"display:flex;gap:4px;font-size:22px;flex-wrap:wrap;justify-content:center\"></div>\n      <div class=\"end-msg\">لقد نفدت قلوبك العشرة<br>حظ موفق في المرة القادمة!</div>\n      <div class=\"score-box\">\n        <div class=\"score-num\" id=\"goScoreNum\">0</div>\n        <div class=\"score-lbl\">نقطة قبل انتهاء الجولة</div>\n      </div>\n    </div>\n    <div class=\"action-row\">\n      <button class=\"btn-prim\" onclick=\"goQuiz()\"><i class=\"ti ti-refresh\" style=\"font-size:16px\"></i> حاول مجدداً</button>\n      <button class=\"btn-sec\" onclick=\"goHome()\"><i class=\"ti ti-home\" style=\"font-size:16px\"></i> الرئيسية</button>\n    </div>\n  </div>\n\n  <!-- ██ RESULT ██ -->\n  <div class=\"screen\" id=\"sResult\">\n    <div class=\"end-card\">\n      <div class=\"end-icon\" id=\"resIcon\"></div>\n      <div class=\"stars-row\" id=\"starsRow\"></div>\n      <div class=\"end-title\" id=\"resTitle\" style=\"color:#2d2566\"></div>\n      <div class=\"end-msg\" id=\"resMsg\"></div>\n      <div class=\"score-box\">\n        <div class=\"score-num\" id=\"resScoreNum\">0</div>\n        <div class=\"score-lbl\" id=\"resScoreLbl\">من أصل 2000 نقطة</div>\n      </div>\n      <div class=\"stat-pills\" id=\"statPills\"></div>\n    </div>\n    <div class=\"action-row\">\n      <button class=\"btn-prim\" onclick=\"goQuiz()\"><i class=\"ti ti-refresh\" style=\"font-size:16px\"></i> العب مجدداً</button>\n      <button class=\"btn-sec\" onclick=\"goHome()\"><i class=\"ti ti-home\" style=\"font-size:16px\"></i> الرئيسية</button>\n    </div>\n  </div>\n\n</div>\n\n<script>\n/* ══════════════════════════════════════════\n   بنك الأسئلة — 23 سؤالاً (يُختار 20 عشوائياً)\n══════════════════════════════════════════ */\nconst qs=[\n  { q:\"\\u0645\\u062A\\u0649 \\u062F\\u062E\\u0644 \\u0627\\u0644\\u0645\\u063A\\u0631\\u0628 \\u062A\\u062D\\u062A \\u0646\\u0638\\u0627\\u0645 \\u0627\\u0644\\u062D\\u0645\\u0627\\u064A\\u0629 \\u0627\\u0644\\u0641\\u0631\\u0646\\u0633\\u064A\\u0629\\u061F\", opts:[\"1910\",\"1912\",\"1956\",\"1899\"], ans:1 },\n  { q:\"\\u0641\\u064A \\u0623\\u064A \\u0633\\u0646\\u0629 \\u062D\\u0635\\u0644 \\u0627\\u0644\\u0645\\u063A\\u0631\\u0628 \\u0639\\u0644\\u0649 \\u0627\\u0633\\u062A\\u0642\\u0644\\u0627\\u0644\\u0647\\u061F\", opts:[\"1944\",\"1956\",\"1962\",\"1975\"], ans:1 },\n  { q:\"\\u0645\\u062A\\u0649 \\u062A\\u0623\\u0633\\u0633 \\u062C\\u0647\\u0627\\u0632 \\u0627\\u0644\\u0623\\u0645\\u0646 \\u0627\\u0644\\u0648\\u0637\\u0646\\u064A \\u0627\\u0644\\u0645\\u063A\\u0631\\u0628\\u064A (DGSN)\\u061F\", opts:[\"16 \\u0645\\u0627\\u064A 1956\",\"14 \\u0645\\u0627\\u064A 1956\",\"06 \\u0646\\u0648\\u0646\\u0628\\u0631 1975\",\"11 \\u064A\\u0646\\u0627\\u064A\\u0631 1944\"], ans:0 },\n  { q:\"\\u0645\\u062A\\u0