973\",\"1975\",\"1979\",\"1982\"], ans:2 },\n  { q:\"\\u0645\\u062A\\u0649 \\u0627\\u0646\\u062F\\u0644\\u0639\\u062A \\u0627\\u0644\\u0623\\u0632\\u0645\\u0629 \\u0627\\u0644\\u0627\\u0642\\u062A\\u0635\\u0627\\u062F\\u064A\\u0629 \\u0627\\u0644\\u0643\\u0628\\u0631\\u0649 \\u0641\\u064A \\u0627\\u0644\\u0648\\u0644\\u0627\\u064A\\u0627\\u062A \\u0627\\u0644\\u0645\\u062A\\u062D\\u062F\\u0629\\u061F\", opts:[\"1914\",\"1929\",\"1939\",\"2008\"], ans:1 },\n  { q:\"\\u0643\\u0645 \\u0639\\u062F\\u062F \\u0627\\u0644\\u062F\\u0648\\u0644 \\u0627\\u0644\\u0623\\u0639\\u0636\\u0627\\u0621 \\u0641\\u064A \\u0627\\u0644\\u0627\\u062A\\u062D\\u0627\\u062F \\u0627\\u0644\\u0623\\u0648\\u0631\\u0648\\u0628\\u064A \\u062D\\u0627\\u0644\\u064A\\u0627\\u064B\\u061F\", opts:[\"22\",\"25\",\"27\",\"30\"], ans:2 },\n  { q:\"\\u0645\\u0646 \\u0647\\u064A \\u0627\\u0644\\u062C\\u0647\\u0629 \\u0627\\u0644\\u062A\\u064A \\u062A\\u0645\\u062B\\u0644 \\u0627\\u0644\\u0633\\u0644\\u0637\\u0629 \\u0627\\u0644\\u062A\\u0646\\u0641\\u064A\\u0630\\u064A\\u0629 \\u0641\\u064A \\u0627\\u0644\\u0645\\u063A\\u0631\\u0628\\u061F\", opts:[\"\\u0627\\u0644\\u0628\\u0631\\u0644\\u0645\\u0627\\u0646\",\"\\u0627\\u0644\\u062D\\u0643\\u0648\\u0645\\u0629\",\"\\u0627\\u0644\\u0642\\u0636\\u0627\\u0621\",\"\\u0627\\u0644\\u0645\\u062C\\u0627\\u0644\\u0633 \\u0627\\u0644\\u0645\\u062D\\u0644\\u064A\\u0629\"], ans:1 },\n  { q:\"\\u0623\\u064A \\u0645\\u0624\\u0633\\u0633\\u0629 \\u062A\\u0645\\u062B\\u0644 \\u0627\\u0644\\u0633\\u0644\\u0637\\u0629 \\u0627\\u0644\\u062A\\u0634\\u0631\\u064A\\u0639\\u064A\\u0629 \\u0641\\u064A \\u0627\\u0644\\u0645\\u063A\\u0631\\u0628\\u061F\", opts:[\"\\u0627\\u0644\\u062D\\u0643\\u0648\\u0645\\u0629\",\"\\u0627\\u0644\\u0628\\u0631\\u0644\\u0645\\u0627\\u0646\",\"\\u0627\\u0644\\u0645\\u062C\\u0644\\u0633 \\u0627\\u0644\\u062F\\u0633\\u062A\\u0648\\u0631\\u064A\",\"\\u0627\\u0644\\u0645\\u062D\\u0627\\u0643\\u0645\"], ans:1 },\n  { q:\"\\u0643\\u0645 \\u0639\\u062F\\u06